*/

export const COLORS = {
  DARK: 0x4A3728,
  LIGHT: 0x654321,
  WHITE: 0xF0F0F0,
  GOLD: 0xFFD700,
  BLACK: 0x111111,
  WOOD: 0x3B2F2F,
  GREEN: 0x228B22,
  TALON: 0xE5C100,
};

export const CONFIG = {
  VOXEL_SIZE: 1,
  FLOOR_Y: -12,
  BG_COLOR: 0xf0f2f5, // Matches Tailwind slate-100/gray-100 roughly
};/**
