import { VoxelData } from '../types';
import { COLORS, CONFIG } from './voxelConstants';

// Helper to prevent overlapping voxels
function setBlock(map: Map<string, VoxelData>, x: number, y: number, z: number, color: number) {
    const rx = Math.round(x);
    const ry = Math.round(y);
    const rz = Math.round(z);
    const key = `${rx},${ry},${rz}`;
    map.set(key, { x: rx, y: ry, z: rz, color });
}

function generateSphere(map: Map<string, VoxelData>, cx: number, cy: number, cz: number, r: number, col: number, sy = 1) {
    const r2 = r * r;
    const xMin = Math.floor(cx - r);
    const xMax = Math.ceil(cx + r);
    const yMin = Math.floor(cy - r * sy);
    const yMax = Math.ceil(cy + r * sy);
    const zMin = Math.floor(cz - r);
    const zMax = Math.ceil(cz + r);

    for (let x = xMin; x <= xMax; x++) {
        for (let y = yMin; y <= yMax; y++) {
            for (let z = zMin; z <= zMax; z++) {
                const dx = x - cx;
                const dy = (y - cy) / sy;
                const dz = z - cz;
                if (dx * dx + dy * dy + dz * dz <= r2) {
                    setBlock(map, x, y, z, col);
                }
            }
        }
    }
}

function generateTree(map: Map<string, VoxelData>, x: number, z: number, yBase: number) {
    // Trunk
    for (let i = 0; i < 4; i++) setBlock(map, x, yBase + i, z, COLORS.WOOD);
    // Leaves
    generateSphere(map, x, yBase + 4, z, 2.5, COLORS.UTD_GREEN);
}

export const Generators = {
    UTDCampus: (): VoxelData[] => {
        const map = new Map<string, VoxelData>();
        const FLOOR = CONFIG.FLOOR_Y + 1;

        // --- The Mall (Ground) ---
        for (let x = -20; x <= 20; x++) {
            for (let z = -20; z <= 20; z++) {
                // Central walkway
                if (Math.abs(x) < 6) {
                    setBlock(map, x, FLOOR, z, COLORS.UTD_CONCRETE);
                } else {
                    // Grass lawns
                    setBlock(map, x, FLOOR, z, COLORS.UTD_GREEN);
                }
            }
        }

        // --- The Trellis (Iconic UTD Feature) ---
        // White square frames along the path
        for (let z = -15; z <= 15; z += 5) {
            // Columns
            for (let y = 0; y < 6; y++) {
                setBlock(map, -4, FLOOR + y, z, COLORS.WHITE);
                setBlock(map, 4, FLOOR + y, z, COLORS.WHITE);
            }
            // Top beam
            for (let x = -4; x <= 4; x++) {
                setBlock(map, x, FLOOR + 6, z, COLORS.WHITE);
            }
            // Side beams connection (longitudinal)
            if (z < 15) {
                for (let dz = 1; dz < 5; dz++) {
                    setBlock(map, -4, FLOOR + 6, z + dz, COLORS.WHITE);
                    setBlock(map, 4, FLOOR + 6, z + dz, COLORS.WHITE);
                }
                // Lattice effect on top
                for (let x = -3; x <= 3; x += 2) {
                    for (let dz = 1; dz < 5; dz++) {
                         setBlock(map, x, FLOOR + 6, z + dz, COLORS.WHITE);
                    }
                }
            }
        }

        // --- The Plinth (Fountain Area) ---
        // Central feature
        const plinthZ = 0;
        for (let x = -3; x <= 3; x++) {
            for (let z = -3; z <= 3; z++) {
                setBlock(map, x, FLOOR + 1, z, COLORS.UTD_CONCRETE);
            }
        }
        // Water
        for (let x = -2; x <= 2; x++) {
            for (let z = -2; z <= 2; z++) {
                setBlock(map, x, FLOOR + 1.5, z, COLORS.WATER);
            }
        }
        // Fountain mist (particles)
        setBlock(map, 0, FLOOR + 2, 0, COLORS.WHITE);
        setBlock(map, 0, FLOOR + 3, 0, COLORS.WHITE);

        // --- Buildings (Founders / Student Union style) ---
        // Blocky, Brutalist, Brick

        // Building Left
        for (let x = -18; x <= -10; x++) {
            for (let z = -10; z <= 10; z++) {
                for (let y = 0; y < 10; y++) {
                    const isWindow = (y % 3 === 1) && (z % 2 !== 0) && (x === -10);
                    setBlock(map, x, FLOOR + y, z, isWindow ? COLORS.GLASS : COLORS.BRICK);
                }
            }
        }

        // Building Right
        for (let x = 10; x <= 18; x++) {
             for (let z = -12; z <= 8; z++) {
                for (let y = 0; y < 12; y++) {
                    const isWindow = (y % 3 === 1) && (z % 2 !== 0) && (x === 10);
                    setBlock(map, x, FLOOR + y, z, isWindow ? COLORS.GLASS : COLORS.UTD_ORANGE);
                }
            }
        }

        // --- Trees ---
        generateTree(map, -8, -15, FLOOR);
        generateTree(map, -8, 15, FLOOR);
        generateTree(map, 8, -15, FLOOR);
        generateTree(map, 8, 15, FLOOR);

        return Array.from(map.values());
    },

    Eagle: (): VoxelData[] => {
        const map = new Map<string, VoxelData>();
        // Branch
        for (let x = -8; x < 8; x++) {
            const y = Math.sin(x * 0.2) * 1.5;
            const z = Math.cos(x * 0.1) * 1.5;
