                    <motion.div key={i} initial={{ opacity: 0, y: 20 }} whileInView={{ opacity: 1, y: 0 }} transition={{ delay: i * 0.1 }} className="group border border-slate-800 bg-slate-900 hover:bg-[#02040A] p-8">
